// The Payload containing the element's data and the head of its energy list
// The Unified Payload
struct ElementEntry {
    int z;                  
    string symbol;     
    double atomic_mass;     
    
    // Existing Data
    EnergyNode* energy_list_head;   
    vector<StandardEnergyData> standard_data;

    // ---> NEW: Head of the linked list for the 76 isotope energies
    IsotopeEnergyNode* isotope_head;

    ElementEntry(int atomic_num, string sym, double mass) : 
        z(atomic_num), symbol(sym), atomic_mass(mass), 
        energy_list_head(nullptr), isotope_head(nullptr) {} 
};
struct HashNode {
    std::string symbol;
    int z;
    HashNode* next;
    HashNode(std::string sym, int atomic_num) : symbol(sym), z(atomic_num), next(nullptr) {}
};
struct ZeqResult {
    double energy;
    double zeq;
};
class SymbolHashMap {
private:
    static const int TABLE_SIZE = 251; // Prime number
    HashNode* table[TABLE_SIZE];

    // Polynomial rolling hash function
    int hashFunction(const std::string& symbol) {
        int hash = 0;
        for (char c : symbol) {
            hash = (hash * 31 + c) % TABLE_SIZE;
        }
        return hash;
    }

public:
    SymbolHashMap() {
        for (int i = 0; i < TABLE_SIZE; i++) table[i] = nullptr;
    }

    // Maps a Symbol to an Atomic Number
    void put(std::string symbol, int z) {
        int index = hashFunction(symbol);
        HashNode* newNode = new HashNode(symbol, z);
        
        // Handle Collisions (Chaining)
        if (table[index] == nullptr) {
            table[index] = newNode;
        } else {
            HashNode* current = table[index];
            while (current->next != nullptr) {
                if (current->symbol == symbol) return; // Prevent duplicates
                current = current->next;
            }
            current->next = newNode;
        }
    }

    // Retrieves Atomic Number from Symbol. Returns -1 if not found.
    int get(std::string symbol) {
        int index = hashFunction(symbol);
        HashNode* current = table[index];
        while (current != nullptr) {
            if (current->symbol == symbol) return current->z;
            current = current->next;
        }
        return -1; 
    }
};
class PeriodicDatabase {
private:
    // The Primary Data Store: Perfect Hash Array (Z-1)
    ElementEntry* elements[118];
    
    // The Secondary Data Store: String Parser
    SymbolHashMap symbolToZMap;

public:
    PeriodicDatabase() {
        for (int i = 0; i < 118; i++) elements[i] = nullptr;
    }

    // Main Insertion Function (Run this FIRST for all elements)
    void insertElement(int z, std::string symbol, double mass) {
        if (z < 1 || z > 118) {
            std::cout << "Error: Atomic number must be between 1 and 118." << std::endl;
            return;
        }

        // 1. Save the actual payload in the perfect array (Index = Z - 1)
        int index = z - 1;
        elements[index] = new ElementEntry(z, symbol, mass);

        // 2. Register the mapping in the string hash map
        symbolToZMap.put(symbol, z);
    }

    // --- DATA LOADING FUNCTIONS ---
    
    // Load standard 80-energy data
    template <size_t N>
    void loadStandardData(int z, const RawEnergyData (&rawData)[N]) {
        if (z < 1 || z > 118 || !elements[z - 1]) return; // Failsafe
        
        int index = z - 1;
        for (int i = N - 1; i >= 0; i--) {
            EnergyNode* newNode = new EnergyNode(rawData[i].energy, rawData[i].mac);
            newNode->next_energy = elements[index]->energy_list_head;
            elements[index]->energy_list_head = newNode;
        }
    }

    // Load new 76-energy isotope data
    template <size_t N>
    void loadIsotopeData(int z, const IsotopeRawData (&rawData)[N]) {
        if (z < 1 || z > 118 || !elements[z - 1]) return; // Failsafe
        
        int index = z - 1;
        for (int i = N - 1; i >= 0; i--) {
            IsotopeEnergyNode* newNode = new IsotopeEnergyNode(rawData[i].energy, rawData[i].mac, rawData[i].isotope);
            newNode->next = elements[index]->isotope_head;
            elements[index]->isotope_head = newNode;
        }
    }

    // --- RETRIEVAL FUNCTIONS ---

    // Lookup Method 1: By Atomic Number O(1)
    ElementEntry* getElement(int z) {
        if (z < 1 || z > 118) return nullptr;
        return elements[z - 1];
    }

    // Lookup Method 2: By Chemical Symbol O(1) average
    ElementEntry* getElement(std::string symbol) {
        // First, get the atomic number from our string map
        int z = symbolToZMap.get(symbol);
        
        // If found, route it through the integer lookup
        if (z != -1) {
            return getElement(z);
        }
        return nullptr;
    }
};
