    // 1. Fetch Hydrogen (Z=1) from your hash table
    void pruneSkipList(ElementEntry* element) {
    if (!element || !element->energy_list_head) return;

    // --- Pass 1: Prune the linear next_energy list ---
    EnergyNode* current = element->energy_list_head;
    
    // Handle the head separately if it needs to be deleted
    while (current != nullptr && ALLOWED_ENERGIES.find(current->energy) == ALLOWED_ENERGIES.end()) {
        EnergyNode* temp = current;
        current = current->next_energy;
        delete temp; // Free memory
    }
    element->energy_list_head = current;

    // Prune the rest of the list
    if (current != nullptr) {
        EnergyNode* prev = current;
        EnergyNode* next_node = current->next_energy;
        
        while (next_node != nullptr) {
            if (ALLOWED_ENERGIES.find(next_node->energy) == ALLOWED_ENERGIES.end()) {
                // Not in the 80 energies list, delete it
                prev->next_energy = next_node->next_energy;
                delete next_node;
                next_node = prev->next_energy;
            } else {
                // Keep it and move forward
                prev = next_node;
                next_node = next_node->next_energy;
            }
        }
    }

    // --- Pass 2: Rebuild next_standard skip pointers ---
    // After deletion, old skip-pointers might point to deallocated memory.
    EnergyNode* rebuild_ptr = element->energy_list_head;
    EnergyNode* last_standard = nullptr;

    while (rebuild_ptr != nullptr) {
        // Clear old skip pointer to avoid dangling references
        rebuild_ptr->next_standard = nullptr;

        if (rebuild_ptr->is_standard) {
            if (last_standard != nullptr) {
                last_standard->next_standard = rebuild_ptr;
            }
            last_standard = rebuild_ptr;
        }
        rebuild_ptr = rebuild_ptr->next_energy;
    }
}
map<string, double> parseCompound(string formula, double mixtureCoeff, PeriodicDatabase &db) {
    // Trim any trailing/leading whitespace first
    size_t first = formula.find_first_not_of(" \t\r\n");
    if (first == string::npos) {
        throw runtime_error("Error: Empty or blank chemical formula component.");
    }
    size_t last = formula.find_last_not_of(" \t\r\n");
    formula = formula.substr(first, (last - first + 1));

    map<string, double> compoundElements;
    int i = 0, n = formula.size();

    while (i < n) {
        if (isupper(formula[i])) {
            string symbol = "";
            symbol += formula[i++];
            while (i < n && islower(formula[i])) {
                symbol += formula[i++];
            }

            // ERROR CHECK: Verify element exists in the database
            if (db.getElement(symbol) == nullptr) {
                throw runtime_error("Error: Element '" + symbol + "' does not exist in the database.");
            }

            string num = "";
            while (i < n && (isdigit(formula[i]) || formula[i] == '.')) {
                num += formula[i++];
            }
            double count = (num == "") ? 1.0 : stod(num);
            
            compoundElements[symbol] += (count * mixtureCoeff);
        } else {
            // Any character here is invalid because it does not start a valid element (which must be uppercase)
            throw runtime_error("Error: Invalid character '" + string(1, formula[i]) + "' in chemical formula '" + formula + "'. Formulas must consist of elements starting with uppercase letters (e.g., H2O, PbO).");
        }
    }

    if (compoundElements.empty()) {
        throw runtime_error("Error: Formula '" + formula + "' could not be parsed into any valid chemical elements.");
    }

    return compoundElements;
}
struct MoleFractionResult {
    string symbol;
    double weightFraction;
    double moleFraction;
};
vector<MoleFractionResult> calculateMoleFractions(string input, PeriodicDatabase &db, bool isWeightBasis = false) {
    map<string, double> totalElementMoles;
    vector<MoleFractionResult> final_results;
    double coefficientSum = 0.0;

    stringstream ss(input);
    string term;

    try {
        while (getline(ss, term, '+')) {
            // Trim spaces
            size_t first = term.find_first_not_of(" ");
            if (string::npos == first) continue;
            size_t last = term.find_last_not_of(" ");
            term = term.substr(first, (last - first + 1));

            int i = 0;
            string coeffStr = "";
            while (i < term.size() && (isdigit(term[i]) || term[i] == '.')) {
                coeffStr += term[i++];
            }

            double coeff = (coeffStr == "") ? 1.0 : stod(coeffStr);
            coefficientSum += coeff;

            string formula = term.substr(i);
            map<string, double> parsed = parseCompound(formula, 1.0, db);

            if (isWeightBasis) {
                double molarMass = 0.0;
                for (auto const& p : parsed) {
                    ElementEntry* el = db.getElement(p.first);
                    if (el) molarMass += p.second * el->atomic_mass;
                }
                if (molarMass > 0) {
                    double moles = coeff / molarMass;
                    for (auto const& p : parsed) {
                        totalElementMoles[p.first] += p.second * moles;
                    }
                }
            } else {
                for (auto const& p : parsed) {
                    totalElementMoles[p.first] += p.second * coeff;
                }
            }
        }

        double grandTotalMoles = 0.0;
        double grandTotalWeight = 0.0;
        map<string, double> elementWeights;

        // Step 1: Calculate global totals
        for (auto const& p : totalElementMoles) {
            grandTotalMoles += p.second;
            ElementEntry* el = db.getElement(p.first);
            if (el != nullptr) {
                double weight = p.second * el->atomic_mass;
                elementWeights[p.first] = weight;
                grandTotalWeight += weight;
            }
        }

        // BUG 6 FIX: Guard against division by zero
        if (grandTotalMoles <= 0.0 || grandTotalWeight <= 0.0) {
            throw runtime_error("Error: Could not calculate mole fractions — no valid elements found in '" + input + "'.");
        }

        // Step 2: Print headers
        cout << "\nAnalysis for Mixture: " << input << endl;
        cout << "------------------------------------------------" << endl;
        cout << "Element | Weight Fraction | Mole Fraction" << endl;
        cout << "------------------------------------------------" << endl;
        
        // Step 3: Calculate individual fractions and populate vector
        for (auto const& p : totalElementMoles) {
            double moleFrac = p.second / grandTotalMoles;
            double weightFrac = elementWeights[p.first] / grandTotalWeight;
            
            // Save to vector
            MoleFractionResult res;
            res.symbol = p.first;
            res.weightFraction = weightFrac;
            res.moleFraction = moleFrac;
            final_results.push_back(res);

            // Print to console
            printf("%-7s | %-15.6f | %.6f\n", p.first.c_str(), weightFrac, moleFrac);
        }
        cout << "------------------------------------------------" << endl;

    } catch (const exception& e) {
        cout << "[ERROR] " << e.what() << endl;
    }

    return final_results;
}

