    double oxygenPackingDensity = 0.0;
    double oxygenMolarVolume = 0.0;
    double ionConcentration = 0.0;
    double interIonicDistance = 0.0;
    double polaronRadius = 0.0;
    double fieldStrength = 0.0;
    
    // MM model mechanical
    double packingDensity = 0.0;
    double dissociationEnergy = 0.0;
    double youngsModulus = 0.0;
    double bulkModulus = 0.0;
    double shearModulus = 0.0;
    double longitudinalModulus = 0.0;
    double poissonsRatio = 0.0;
    double hardness = 0.0;
    double fractalBondConnectivity = 0.0;
    
    // Optical
    double refractiveIndex = 0.0;
    double molarRefractivity = 0.0;
    double molarPolarizability = 0.0;
    double metallization = 0.0;
    double reflectionLoss = 0.0;
