struct CompoundData {
    double molarMass = 0.0;
    double packingFactor = 0.0;
    double dissociationEnergy = 0.0;
    double refractiveIndex = 1.5;
};

inline CompoundData getCompoundData(const std::string& formula, PeriodicDatabase& db) {
    CompoundData data;
    
    try {
        std::map<std::string, double> parsed = parseCompound(formula, 1.0, db);
        for (auto const& p : parsed) {
            ElementEntry* el = db.getElement(p.first);
            if (el) {
                data.molarMass += p.second * el->atomic_mass;
            }
        }
    } catch (...) {}
    
    std::string normalized = formula;
    size_t first = normalized.find_first_not_of(" ");
    if (first != std::string::npos) {
        size_t last = normalized.find_last_not_of(" ");
        normalized = normalized.substr(first, (last - first + 1));
    }
    
    if (normalized == "SiO2") {
        data.packingFactor = 14.0;
        data.dissociationEnergy = 3040.0;
        data.refractiveIndex = 1.46;
        return data;
    }
    if (normalized == "B2O3") {
        data.packingFactor = 20.8;
        data.dissociationEnergy = 3560.0;
        data.refractiveIndex = 1.46;
        return data;
    }
    if (normalized == "P2O5") {
        data.packingFactor = 34.0;
        data.dissociationEnergy = 6280.0;
        data.refractiveIndex = 1.45;
        return data;
    }
    if (normalized == "PbO") {
        data.packingFactor = 11.5;
        data.dissociationEnergy = 760.0;
        data.refractiveIndex = 2.23;
        return data;
    }
    if (normalized == "Na2O") {
        data.packingFactor = 11.2;
        data.dissociationEnergy = 1000.0;
        data.refractiveIndex = 1.50;
        return data;
    }
    if (normalized == "Li2O") {
        data.packingFactor = 8.3;
        data.dissociationEnergy = 1380.0;
        data.refractiveIndex = 1.60;
        return data;
    }
    if (normalized == "K2O") {
        data.packingFactor = 17.0;
        data.dissociationEnergy = 860.0;
        data.refractiveIndex = 1.50;
        return data;
    }
    if (normalized == "CaO") {
        data.packingFactor = 10.5;
        data.dissociationEnergy = 1060.0;
        data.refractiveIndex = 1.83;
        return data;
    }
    if (normalized == "MgO") {
        data.packingFactor = 8.0;
        data.dissociationEnergy = 920.0;
        data.refractiveIndex = 1.74;
        return data;
    }
    if (normalized == "BaO") {
        data.packingFactor = 13.5;
        data.dissociationEnergy = 960.0;
        data.refractiveIndex = 1.98;
        return data;
    }
    if (normalized == "Al2O3") {
        data.packingFactor = 21.5;
        data.dissociationEnergy = 3180.0;
        data.refractiveIndex = 1.76;
        return data;
    }
    if (normalized == "Fe2O3") {
        data.packingFactor = 25.5;
        data.dissociationEnergy = 2380.0;
        data.refractiveIndex = 2.90;
        return data;
    }
    if (normalized == "ZnO") {
        data.packingFactor = 9.2;
        data.dissociationEnergy = 900.0;
        data.refractiveIndex = 2.00;
        return data;
    }
    if (normalized == "TiO2") {
        data.packingFactor = 14.5;
        data.dissociationEnergy = 1860.0;
        data.refractiveIndex = 2.61;
        return data;
    }
    if (normalized == "Bi2O3") {
        data.packingFactor = 27.0;
        data.dissociationEnergy = 1430.0;
        data.refractiveIndex = 2.45;
        return data;
    }
    if (normalized == "TeO2") {
        data.packingFactor = 17.5;
        data.dissociationEnergy = 1250.0;
        data.refractiveIndex = 2.20;
        return data;
    }
    
    double sumRadiiCubed = 0.0;
    double totalAtoms = 0.0;
    try {
        std::map<std::string, double> parsed = parseCompound(formula, 1.0, db);
        for (auto const& p : parsed) {
            double r = getIonicRadius(p.first);
            sumRadiiCubed += p.second * std::pow(r, 3.0);
            totalAtoms += p.second;
        }
    } catch (...) {}
    
    data.packingFactor = 2.522 * sumRadiiCubed;
    data.dissociationEnergy = totalAtoms * 500.0;
    
    double weightedN = 0.0;
    double totalWeight = 0.0;
    try {
        std::map<std::string, double> parsed = parseCompound(formula, 1.0, db);
        for (auto const& p : parsed) {
            ElementEntry* el = db.getElement(p.first);
            if (el) {
                double elN = 1.4 + 0.01 * el->z;
                if (p.first == "O" || p.first == "F") elN = 1.3;
                weightedN += p.second * elN;
                totalWeight += p.second;
            }
        }
    } catch (...) {}
    
    data.refractiveIndex = totalWeight > 0.0 ? (weightedN / totalWeight) : 1.5;
    return data;
}

inline BulkProperties calculateBulkProperties(const std::string& input, double density, PeriodicDatabase& db, const std::string& targetIon = "", double eg = 0.0, const std::string& cnStr = "") {
    BulkProperties props;
    if (density <= 0.0) return props;
    
    std::vector<std::pair<std::string, double>> compoundList;
    double coeffSum = 0.0;
    
    std::stringstream ss(input);
    std::string term;
    
    try {
        while (std::getline(ss, term, '+')) {
            size_t first = term.find_first_not_of(" ");
            if (std::string::npos == first) continue;
            size_t last = term.find_last_not_of(" ");
            term = term.substr(first, (last - first + 1));
            
            int i = 0;
            std::string coeffStr = "";
            while (i < term.size() && (isdigit(term[i]) || term[i] == '.')) {
                coeffStr += term[i++];
            }
            double coeff = (coeffStr == "") ? 1.0 : stod(coeffStr);
            coeffSum += coeff;
            
            std::string formula = term.substr(i);
            compoundList.push_back({formula, coeff});
        }
    } catch (...) {
        return props;
    }
    
    if (coeffSum <= 0.0) return props;
    
    std::vector<int> cnList;
    {
        std::stringstream cnSS(cnStr);
        int tempCn;
        while (cnSS >> tempCn) {
            cnList.push_back(tempCn);
        }
    }
    
    double sumM = 0.0;
    double sumPackingFactor = 0.0;
    double sumDissEnergy = 0.0;
    double sumRefractiveIndex = 0.0;
    double sumPackingDensity = 0.0;
    double sumDissociationEnergy = 0.0;
    
    double totalMolesOfB = 0.0;
    double totalMolesOfO = 0.0;
    double totalMolesOfCations = 0.0;
    double weightedCationValencySum = 0.0;
    double moleFracOfBCompounds = 0.0; // X_B2O3: mole fraction of B-containing compounds (e.g. B2O3)

    
    for (size_t k = 0; k < compoundList.size(); ++k) {
        const auto& c = compoundList[k];
        double normCoeff = c.second / coeffSum;
        CompoundData data = getCompoundData(c.first, db);
        
        int cn = 6;
        if (k < cnList.size()) {
            cn = cnList[k];
        }
        
        CNProps excelProps = getExcelOxideCNProps(c.first, cn);
        if (excelProps.packingFactor >= 0.0) {
            data.packingFactor = excelProps.packingFactor;
        }
        if (excelProps.dissociationEnergy >= 0.0) {
            data.dissociationEnergy = excelProps.dissociationEnergy;
        }
        
        sumM += normCoeff * data.molarMass;
        sumPackingFactor += normCoeff * data.packingFactor;
        sumDissEnergy += normCoeff * data.dissociationEnergy;
        sumRefractiveIndex += normCoeff * data.refractiveIndex;
        
        if (data.molarMass > 0.0) {
            sumPackingDensity += normCoeff * (data.packingFactor);
            sumDissociationEnergy += normCoeff * (data.dissociationEnergy);
        }
        
        try {
            std::map<std::string, double> parsed = parseCompound(c.first, normCoeff, db);
            bool compHasB = false;
            for (auto const& p : parsed) {
                if (p.first == "B") {
                    totalMolesOfB += p.second;
                    compHasB = true;
                }
                if (p.first == "O") {
                    totalMolesOfO += p.second;
                } else {
                    bool isTarget = false;
                    if (!targetIon.empty()) {
                        isTarget = (p.first == targetIon);
                    } else {
                        isTarget = (p.first != "F" && p.first != "Cl" && p.first != "Br" && p.first != "I" && p.first != "S" && p.first != "Se");
                    }
                    if (isTarget) {
                        totalMolesOfCations += p.second;
                        
                        double valency = 2.0;
                        std::string sym = p.first;
                        
                        // Dynamically calculate valency from compound anions
                        double totalAnionCharge = 0.0;
                        double cationCount = 0.0;
                        try {
                            std::map<std::string, double> formulaElements = parseCompound(c.first, 1.0, db);
                            for (auto const& el : formulaElements) {
                                std::string elSym = el.first;
                                double elCount = el.second;
                                if (elSym == "O") {
                                    totalAnionCharge += elCount * 2.0;
                                } else if (elSym == "S") {
                                    totalAnionCharge += elCount * 2.0;
                                } else if (elSym == "F" || elSym == "Cl" || elSym == "Br" || elSym == "I") {
                                    totalAnionCharge += elCount * 1.0;
                                }
                            }
                            cationCount = formulaElements[sym];
                        } catch (...) {}
                        
                        if (totalAnionCharge > 0.0 && cationCount > 0.0) {
                            valency = totalAnionCharge / cationCount;
                        } else {
                            // Fallback to the chart
                            if (sym == "Li" || sym == "Na" || sym == "K" || sym == "Rb" || sym == "Cs" || sym == "H") valency = 1.0;
                            else if (sym == "Be" || sym == "Mg" || sym == "Ca" || sym == "Sr" || sym == "Ba" || sym == "Zn" || sym == "Cd" || sym == "Pb") valency = 2.0;
                            else if (sym == "B" || sym == "Al" || sym == "Ga" || sym == "In" || sym == "Sc" || sym == "Y" || sym == "La" || sym == "Gd" || sym == "Lu" || sym == "Fe"|| sym == "Bi") valency = 3.0;
                            else if (sym == "Si" || sym == "Ge" || sym == "Sn" || sym == "Ti" || sym == "Zr" || sym == "Hf" || sym == "Th"|| sym == "Te") valency = 4.0;
                            else if (sym == "P" || sym == "As" || sym == "Sb"  || sym == "V" || sym == "Nb" || sym == "Ta") valency = 5.0;
                            else if (sym == "Cr" || sym == "Mo" || sym == "W") valency = 6.0;
                        }
                        
                        weightedCationValencySum += p.second * valency;
                    }
                }
            }
            if (compHasB) {
                moleFracOfBCompounds += normCoeff; // X_B2O3: mole fraction of this B-containing compound
            }
        } catch (...) {}
    }
    
    props.molarMass = sumM;
    props.molarVolume = sumM / density;
    
    double NA = 6.02214076e23;
    // Formula: <d_B-B> = (Vm / (2 * NA * (1 - X_B2O3)))^(1/3)
    // X_B2O3 = mole fraction of B2O3 (all boron-containing compounds) in the glass
    if (moleFracOfBCompounds > 0.0) {
        double denom = 2.0 * NA * (1.0 - moleFracOfBCompounds);
        if (denom > 0.0) {
            props.avgBoronDistance = std::pow(props.molarVolume / denom, 1.0 / 3.0) * 1e8;
        }
    }
    
    props.oxygenPackingDensity = (totalMolesOfO * density / sumM) * 1000.0;
    props.oxygenMolarVolume = totalMolesOfO > 0.0 ? (props.molarVolume / totalMolesOfO) : 0.0;
    
    if (totalMolesOfCations > 0.0) {
        double N_cat = (totalMolesOfCations * NA) / props.molarVolume;
        props.ionConcentration = N_cat * 1e-21;
        props.interIonicDistance = std::pow(1.0 / N_cat, 1.0 / 3.0) * 1e8;
        props.polaronRadius = 0.5 * std::pow(3.14159265358979323846 / (6.0 * N_cat), 1.0 / 3.0) * 1e8;
        
        double avgValency = weightedCationValencySum / totalMolesOfCations;
        props.fieldStrength = (avgValency / std::pow(props.polaronRadius, 2.0)) * 10.0;
    }
    
    props.packingDensity = sumPackingDensity * density/sumM;
    props.dissociationEnergy = sumDissociationEnergy/4.186;
    
    props.poissonsRatio = 0.5 - 1.0 / (7.2 * props.packingDensity);
    props.youngsModulus = 8.36 * props.packingDensity * props.dissociationEnergy;
    props.bulkModulus = 10.0 * std::pow(props.packingDensity, 2.0) * props.dissociationEnergy;
    
    if (10.2 * props.packingDensity - 1.0 != 0.0) {
        props.shearModulus = (30.0 * std::pow(props.packingDensity, 2.0) * props.dissociationEnergy) / (10.2 * props.packingDensity - 1.0);
    } else {
        props.shearModulus = props.youngsModulus / (2.0 * (1.0 + props.poissonsRatio));
    }
    props.longitudinalModulus = props.bulkModulus + (4.0 / 3.0) * props.shearModulus;
    props.hardness = (props.youngsModulus * (1.0 - 2.0 * props.poissonsRatio)) / (6.0 * (1.0 + props.poissonsRatio));
    if (props.bulkModulus > 0.0) {
        props.fractalBondConnectivity = (4.0 * props.shearModulus) / props.bulkModulus;
    } else {
        props.fractalBondConnectivity = 0.0;
    }
    
    props.refractiveIndex = sumRefractiveIndex;
    if (eg > 0.0) {
        double A_ds = 1.0 - std::sqrt(eg / 20.0);
        if (A_ds >= 0.0 && A_ds < 1.0) {
            props.refractiveIndex = std::sqrt((2.0 * A_ds + 1.0) / (1.0 - A_ds));
        }
    }
    double n = props.refractiveIndex;
    props.dielectricConstant = std::pow(n, 2.0);
    props.optDielectricConstant = std::pow(n, 2.0)-1;
    props.reflectionLoss = std::pow((n - 1.0) / (n + 1.0), 2.0);
    props.molarRefractivity = props.molarVolume * (std::pow(n, 2.0) - 1.0) / (std::pow(n, 2.0) + 2.0);
    props.metallization = 1.0 - (props.molarRefractivity / props.molarVolume);
    props.molarPolarizability = 0.3964 * props.molarRefractivity;
    props.electronicPolarizability = ((std::pow(n, 2.0) - 1.0) / (std::pow(n, 2.0) + 2.0) )* 0.3964;
    props.transmissionCoefficient = 2.0 * n /( std::pow(n, 2.0)+1);
    if (eg > 0.0) {
        props.optElectronegativity = 2.688*eg;
    }
    props.linearSusceptibility = (std::pow(n, 2.0) - 1.0) / (4.0 * 3.14159265358979323846);
    // BUG 7 FIX: Guard against division by zero when refractive index n == 1
    double nMinus1Pow4 = std::pow(n - 1.0, 4.0);
    props.nonlinearSusceptibility = (nMinus1Pow4 > 1e-30) ? (1.7e-10 / (24886.19831 * nMinus1Pow4)) : 0.0;
    props.nonlinearRefractiveIndex = (12.0 * 3.14159265358979323846 * props.nonlinearSusceptibility) / (n > 0.0 ? n : 1.0);
    
    return props;
}

#include <iomanip>



#include <iomanip>
#include <cmath>

vector<AttenuationResult> calculateProperties(string input, PeriodicDatabase &db, bool useStandardEnergies, bool isWeightBasis = false) {
    map<string, double> parsed;
    vector<AttenuationResult> results;

    stringstream ss(input);
    string term;

    try {
        // 1. Parse the mixture
        while (getline(ss, term, '+')) {
            size_t first = term.find_first_not_of(" ");
            if (string::npos == first) continue;
            size_t last = term.find_last_not_of(" ");
            term = term.substr(first, (last - first + 1));

            int i = 0;
            string coeffStr = "";
            while (i < term.size() && (isdigit(term[i]) || term[i] == '.')) {
                coeffStr += term[i++];
            }
            double coeff = (coeffStr == "") ? 1.0 : stod(coeffStr);

            string formula = term.substr(i);
            map<string, double> tempParsed = parseCompound(formula, 1.0, db);

            if (isWeightBasis) {
                double molarMass = 0.0;
                for (auto const& p : tempParsed) {
                    ElementEntry* el = db.getElement(p.first);
                    if (el) molarMass += p.second * el->atomic_mass;
                }
                if (molarMass > 0) {
                    double moles = coeff / molarMass;
                    for (auto const& p : tempParsed) {
                        parsed[p.first] += p.second * moles;
                    }
                }
            } else {
                for (auto const& p : tempParsed) {
                    parsed[p.first] += p.second * coeff;
                }
            }
        }

        // 2. Setup Components, Weights, and Mole Fractions
        double totalWeight = 0.0;
        double totalMoles = 0.0;
        
        struct Component {
            ElementEntry* element;
            double moles;
            double weightFraction;
            EnergyNode* current_ptr; 
        };
        vector<Component> components;

        // Pass A: Calculate Grand Totals
        for (auto const& p : parsed) {
            totalMoles += p.second;
            ElementEntry* el = db.getElement(p.first);
            if (el != nullptr) {
                totalWeight += (p.second * el->atomic_mass);
            }
        }

        // Pass B: Populate tracking array and Skip-List Pointers
        for (auto const& p : parsed) {
            ElementEntry* el = db.getElement(p.first);
            if (el != nullptr) {
                Component c;
                c.element = el;
                c.moles = p.second;
                c.weightFraction = (p.second * el->atomic_mass) / totalWeight; 
                
                EnergyNode* curr = el->energy_list_head;
                if (useStandardEnergies) {
                    while (curr != nullptr && !curr->is_standard) {
                        curr = curr->next_energy;
                    }
                }
                c.current_ptr = curr;
                components.push_back(c);
            }
        }

        // 3. Propagate and Calculate MAC & Z_eff
        bool moreEnergies = true;
        while (moreEnergies) {
            double currentEnergy = -1.0;
            double mixtureMAC = 0.0;
            
            double z_eff_numerator = 0.0;
            double z_eff_denominator = 0.0;
            
            for (auto &c : components) {
                if (c.current_ptr == nullptr) {
                    moreEnergies = false;
                    break;
                }
                
                if (currentEnergy < 0) {
                    currentEnergy = c.current_ptr->energy;
                }
                
                double mac_i = c.current_ptr->attenuation_coeff;
                
                // A) Calculate MAC mix using Weight Fraction
                mixtureMAC += (c.weightFraction * mac_i);
                
                // B) Calculate Z_eff using Mole Fraction formula
                double f_i = c.moles / totalMoles; // Mole Fraction
                double A_i = c.element->atomic_mass;
                int Z_i = c.element->z;
                
                double fA_MAC = f_i * A_i * mac_i;
                z_eff_numerator += fA_MAC;
                z_eff_denominator += (fA_MAC / Z_i);
                
                // Propagate forward
                if (useStandardEnergies) {
                    c.current_ptr = c.current_ptr->next_standard;
                } else {
                    c.current_ptr = c.current_ptr->next_energy;
                }
            }
            
            // Store the result
          if (moreEnergies) {
                // BUG 4 FIX: Guard against division by zero in Z_eff
                double z_eff = (z_eff_denominator != 0.0) ? (z_eff_numerator / z_eff_denominator) : 0.0;
                
                // --- NEW: Calculate Electron Density (N_e) ---
                // Using: N_e = (Z_eff / M) * N_A * sum(n_i)
                const double AVOGADRO = 6.02214076e23;
                double n_e = (totalWeight > 0.0) ? ((z_eff / totalWeight) * AVOGADRO * totalMoles) : 0.0;

                // Push all three properties to the results array
                results.push_back({currentEnergy, mixtureMAC, z_eff, n_e});
            }
        }

    } catch (const exception& e) {
        cout << "[ERROR] calculateProperties: " << e.what() << endl;
        throw; // BUG 5 FIX: re-throw so the API handler can report the error to the user
    }

    return results;
}
void printPropertiesmac(string input, const vector<AttenuationResult>& results, bool isStandard) {
    if (results.empty()) {
        cout << "No data to display." << endl;
        return;
    }

    if (isStandard) {
        cout << "\nMass Attenuation Coefficients (Standard Energies) for: " << input << endl;
    } else {
        cout << "\nMass Attenuation Coefficients (All Energies) for: " << input << endl;
    }
    
    cout << "---------------------------------------" << endl;
    cout << "Energy (MeV)  |  MAC_mix (cm^2/g)" << endl;
    cout << "---------------------------------------" << endl;

    // Loop through the results and print
    for (const auto& res : results) {
        printf(" %10.6f   | %12.6f\n", res.energy, res.mac);
    }
    cout << "---------------------------------------" << endl;
}
vector<AttenuationResult> printPropertieslac(string input, const vector<AttenuationResult>& results, bool isStandard, double d) {
    vector<AttenuationResult> lac_results;

    if (results.empty()) {
        cout << "No data to display." << endl;
        return lac_results; // Returns an empty vector
    }

    if (isStandard) {
        cout << "\nLinear Attenuation Coefficients (Standard Energies) for: " << input << endl;
    } else {
        cout << "\nLinear Attenuation Coefficients (All Energies) for: " << input << endl;
    }
    
    cout << "---------------------------------------" << endl;
    cout << "Energy (MeV)   |  LAC_mix (cm^-1)" << endl;
    cout << "---------------------------------------" << endl;
    cout << "Density Used: " << d << " g/cm^3" << endl;
    cout << "---------------------------------------" << endl;

    for (const auto& res : results) {
        // Calculate LAC: mu = (mu/rho) * rho
        double lac_value = res.mac * d;
        
        // Store the result in the vector
        // Reusing AttenuationResult: energy remains same, 'mac' field now holds 'lac'
        AttenuationResult temp;
        temp.energy = res.energy;
        temp.mac = lac_value; 
        lac_results.push_back(temp);

        // Print to console
        printf(" %10.6f   | %12.6f\n", res.energy, lac_value);
    }
    
    cout << "---------------------------------------" << endl;
    
    return lac_results; // Return the populated vector
}
