// Helper to prevent Excel crashes on invalid numbers (nan, inf)
void writeSafeCell(ofstream &file, double val) {
    if (std::isnan(val) || std::isinf(val)) {
        file << "   <Cell><Data ss:Type=\"String\">N/A</Data></Cell>\n";
    } else {
        file << "   <Cell><Data ss:Type=\"Number\">" << val << "</Data></Cell>\n";
    }
}

