#include <unordered_set>

inline bool isCompoundAvailableInMechanicalDB(const std::string& formula) {
    std::string norm = formula;
    size_t first = norm.find_first_not_of(" \t\r\n");
    if (first != std::string::npos) {
        size_t last = norm.find_last_not_of(" \t\r\n");
        norm = norm.substr(first, (last - first + 1));
    }
    static const std::unordered_set<std::string> allowed = {
        "V2O3", "GeO2", "B2O3", "V2O5", "SiO2", "TeO2", "As2O5", "Sb2O3", "Sb2O5", "P2O5",
        "Al2O3", "ZrO2", "BeO", "TiO2", "Ga2O3", "ThO2", "Fe2O3", "ZnO", "PbO", "CdO",
        "Ta2O5", "Cr2O3", "MgO", "Nb2O5", "Sc2O3", "Li2O", "Er2O3", "MnO2", "Y2O3", "Ce2O3",
        "Tm2O3", "MoO3", "Nd2O3", "Gd2O3", "CoO", "Pr2O3", "WO3", "Yb2O3", "La2O3", "CaO",
        "SnO2", "Dy2O3", "Sm2O3", "CuO", "Eu2O3", "SrO", "Cu2O", "SnO", "BaO", "PbO2",
        "Na2O", "Bi2O3", "In2O3", "Ag2O", "K2O", "Rb2O", "Cs2O"
    };
    return allowed.count(norm) > 0;
}

inline bool isCompositionAvailableInMechanicalDB(const std::string& composition) {
    std::stringstream ss(composition);
    std::string term;
    try {
        while (std::getline(ss, term, '+')) {
            size_t first = term.find_first_not_of(" \t\r\n");
            if (std::string::npos == first) continue;
            size_t last = term.find_last_not_of(" \t\r\n");
            term = term.substr(first, (last - first + 1));
            int i = 0;
            while (i < term.size() && (isdigit(term[i]) || term[i] == '.')) {
                i++;
            }
            std::string formula = term.substr(i);
            if (!isCompoundAvailableInMechanicalDB(formula)) {
                return false;
            }
        }
    } catch (...) {
        return false;
    }
    return true;
}

string exportMultiCompositionToOriginCSV(
    string materialName, 
    const vector<CompCalculatedData>& compsData,
    const vector<double>& t_values,
    const vector<double>& x_mfp, 
    const set<string>& params,
    const map<double, string>& energyToIsotope,
    bool returnStringOnly,
    PeriodicDatabase& db,
    const string& targetIon = "") 
{
    ostringstream file;

    bool hasIsotopes = !energyToIsotope.empty();
    bool wantMAC  = params.count("mac");
    bool wantLAC  = params.count("lac");
    bool wantMFP  = params.count("mfp");
    bool wantHVL  = params.count("hvl");
    bool wantTVL  = params.count("tvl");
    bool wantZeff = params.count("zeff");
    bool wantNe   = params.count("ne");
    bool wantTF   = params.count("tf");
    bool wantRPE  = params.count("rpe");
    bool wantLeq  = params.count("leq");
    bool hasZeq = params.count("zeq") || params.count("gp") || params.count("ebf") || params.count("eabf");

    bool wantMolarMass = params.count("molar_mass");
    bool wantMolarVol = params.count("molar_vol");
    bool wantAvgBoron = params.count("p-dB_B");
    bool wantOPD = params.count("opd");
    bool wantOxygenVol = params.count("o_molar_vol");
    bool wantIonConc = params.count("ion-conc");
    bool wantInterIonic = params.count("inter_ionic_dist");
    bool wantPolaron = params.count("polaron_radius");
    bool wantFieldStrength = params.count("field_strength");
    
    bool wantPackingDensity = params.count("packing_density");
    bool wantDissEnergy = params.count("dissociation_energy");
    bool wantYoung = params.count("youngs_modulus");
    bool wantBulk = params.count("bulk_modulus");
    bool wantShear = params.count("shear_modulus");
    bool wantLong = params.count("longitudinal_modulus");
    bool wantPoisson = params.count("poissons_ratio");
    bool wantHardness = params.count("hardness");
    bool wantFractal = params.count("fractalbondconnectivity");
    
    bool wantRefIndex = params.count("refractive_index");
    bool wantDielectric = params.count("dielectric_constant");
    bool wantOptDielectric = params.count("opt_dielectric_constant");
    bool wantRefLoss = params.count("reflection_loss");
    bool wantMolarRef = params.count("molar_refractivity");
    bool wantMetallization = params.count("metallization");
    bool wantMolarPolar = params.count("molar_polarizability");
    bool wantElectronicPolar = params.count("electronic_polarizability");
    bool wantOptTrans = params.count("optical_transmission");
    bool wantOptElectroneg = params.count("opt_electronegativity");
    bool wantLinearSuscept = params.count("linear_susceptibility");
    bool wantNonlinearSuscept = params.count("nonlinear_susceptibility");
    bool wantNonlinearRefIndex = params.count("nonlinear_refractive_index");

    bool wantDensity = params.count("density_output") || wantLAC || wantMFP || wantHVL || wantTVL || wantTF || wantRPE || wantLeq || wantMolarVol || wantOPD || wantOxygenVol || wantIonConc || wantInterIonic || wantPolaron || wantFieldStrength || wantPackingDensity || wantDissEnergy || wantYoung || wantBulk || wantShear || wantLong || wantPoisson || wantHardness || wantFractal || wantMolarRef || wantMetallization || wantMolarPolar || wantElectronicPolar || wantOptTrans || wantLinearSuscept || wantNonlinearSuscept || wantNonlinearRefIndex;
    bool wantBandgap = params.count("bandgap_output") || wantRefIndex || wantDielectric || wantOptDielectric || wantRefLoss || wantMolarRef || wantMetallization || wantMolarPolar || wantElectronicPolar || wantOptTrans || wantOptElectroneg || wantLinearSuscept || wantNonlinearSuscept || wantNonlinearRefIndex;
    bool wantCN = wantPackingDensity || wantDissEnergy || wantYoung || wantBulk || wantShear || wantLong || wantPoisson || wantHardness || wantFractal;
    bool wantDopant = wantIonConc || wantInterIonic || wantPolaron || wantFieldStrength;

    // Align all energies by taking the union
    set<double> allEnergies;
    for (const auto& cd : compsData) {
        for (const auto& r : cd.mac) {
            allEnergies.insert(r.energy);
        }
    }
    // Physical-only mode: if no energy data, add a single dummy row so bulk properties are written
    if (allEnergies.empty()) {
        allEnergies.insert(0.0);
    }

    // Row 1: Long Name
    file << "Energy";
    if (hasIsotopes) file << ",Isotope";
    
    for (const auto& cd : compsData) {
        string suffix = " [" + (cd.name.empty() ? cd.formula : cd.name) + "]";
        if (wantMAC) file << ",MAC" << suffix;
        if (wantLAC) file << ",LAC" << suffix;
        if (wantMFP) file << ",MFP" << suffix;
        if (wantHVL) file << ",HVL" << suffix;
        if (wantTVL) file << ",TVL" << suffix;
        if (wantZeff) file << ",Zeff" << suffix;
        if (wantNe) file << ",Ne" << suffix;
        if (wantTF) for (double t : t_values) file << ",TF (t=" << t << ")" << suffix;
        if (wantRPE) for (double t : t_values) file << ",RPE (t=" << t << ")" << suffix;
        if (wantLeq) for (double t : t_values) file << ",Leq (t=" << t << ")" << suffix;
        if (hasZeq) file << ",Zeq" << suffix
                         << ",GP_Abs_b" << suffix << ",GP_Abs_c" << suffix << ",GP_Abs_a" << suffix << ",GP_Abs_Xk" << suffix << ",GP_Abs_d" << suffix
                         << ",GP_Exp_b" << suffix << ",GP_Exp_c" << suffix << ",GP_Exp_a" << suffix << ",GP_Exp_Xk" << suffix << ",GP_Exp_d" << suffix;
        if (params.count("ebf")) for (double x : x_mfp) file << ",EBF (x=" << x << ")" << suffix;
        if (params.count("eabf")) for (double x : x_mfp) file << ",EABF (x=" << x << ")" << suffix;

        if (wantMolarMass) file << ",Molar Mass" << suffix;
        if (wantDensity) file << ",Density" << suffix;
        if (wantCN) file << ",CN" << suffix;
        if (wantBandgap) file << ",Bandgap" << suffix;
        if (wantDopant) file << ",Dopant" << suffix;
        if (wantMolarVol) file << ",Molar Volume" << suffix;
        if (wantAvgBoron) file << ",Avg Boron Distance" << suffix;
        if (wantOPD) file << ",Oxygen Packing Density" << suffix;
        if (wantOxygenVol) file << ",Oxygen Molar Volume" << suffix;
        if (wantIonConc) file << ",Ion Concentration" << suffix;
        if (wantInterIonic) file << ",Inter-ionic Distance" << suffix;
        if (wantPolaron) file << ",Polaron Radius" << suffix;
        if (wantFieldStrength) file << ",Field Strength" << suffix;
        if (wantPackingDensity) file << ",Packing Density" << suffix;
        if (wantDissEnergy) file << ",Dissociation Energy" << suffix;
        if (wantYoung) file << ",Youngs Modulus" << suffix;
        if (wantBulk) file << ",Bulk Modulus" << suffix;
        if (wantShear) file << ",Shear Modulus" << suffix;
        if (wantLong) file << ",Longitudinal Modulus" << suffix;
        if (wantPoisson) file << ",Poissons Ratio" << suffix;
        if (wantHardness) file << ",Vickers Hardness" << suffix;
        if (wantFractal) file << ",Fractal Bond Connectivity" << suffix;
        if (wantRefIndex) file << ",Refractive Index" << suffix;
        if (wantDielectric) file << ",Dielectric Constant" << suffix;
        if (wantOptDielectric) file << ",Optical Dielectric Constant" << suffix;
        if (wantRefLoss) file << ",Reflection Loss" << suffix;
        if (wantMolarRef) file << ",Molar Refractivity" << suffix;
        if (wantMetallization) file << ",Metallization Criterion" << suffix;
        if (wantMolarPolar) file << ",Molar Polarizability" << suffix;
        if (wantElectronicPolar) file << ",Electronic Polarizability" << suffix;
        if (wantOptTrans) file << ",Transmission Coefficient" << suffix;
        if (wantOptElectroneg) file << ",Optical Electronegativity" << suffix;
        if (wantLinearSuscept) file << ",Linear Susceptibility" << suffix;
        if (wantNonlinearSuscept) file << ",Non-linear Susceptibility" << suffix;
        if (wantNonlinearRefIndex) file << ",Non-linear Refractive Index" << suffix;
    }
    file << "\n";
    
    // Row 2: Units
    file << "MeV";
    if (hasIsotopes) file << ",";
    for (const auto& cd : compsData) {
        if (wantMAC) file << ",cm2/g";
        if (wantLAC) file << ",cm-1";
        if (wantMFP) file << ",cm";
        if (wantHVL) file << ",cm";
        if (wantTVL) file << ",cm";
        if (wantZeff) file << ",";
        if (wantNe) file << ",electrons/g";
        if (wantTF) for (size_t i=0; i<t_values.size(); i++) file << ",%";
        if (wantRPE) for (size_t i=0; i<t_values.size(); i++) file << ",%";
        if (wantLeq) for (size_t i=0; i<t_values.size(); i++) file << ",cm";
        if (hasZeq) file << ",,,,,,,,,,,";
        if (params.count("ebf")) for (size_t i=0; i<x_mfp.size(); i++) file << ",";
        if (params.count("eabf")) for (size_t i=0; i<x_mfp.size(); i++) file << ",";

        if (wantMolarMass) file << ",g/mol";
        if (wantDensity) file << ",g/cm3";
        if (wantCN) file << ",dimensionless";
        if (wantBandgap) file << ",eV";
        if (wantDopant) file << ",none";
        if (wantMolarVol) file << ",cm3/mol";
        if (wantAvgBoron) file << ",10^-8 cm";
        if (wantOPD) file << ",g-atom/L";
        if (wantOxygenVol) file << ",cm3/mol";
        if (wantIonConc) file << ",10^21 ions/cm3";
        if (wantInterIonic) file << ",10^-8 cm";
        if (wantPolaron) file << ",10^-8 cm";
        if (wantFieldStrength) file << ",10^15 cm-2";
        if (wantPackingDensity) file << ",dimensionless";
        if (wantDissEnergy) file << ",kJ/cm3";
        if (wantYoung) file << ",GPa";
        if (wantBulk) file << ",GPa";
        if (wantShear) file << ",GPa";
        if (wantLong) file << ",GPa";
        if (wantPoisson) file << ",dimensionless";
        if (wantHardness) file << ",GPa";
        if (wantFractal) file << ",dimensionless";
        if (wantRefIndex) file << ",dimensionless";
        if (wantDielectric) file << ",dimensionless";
        if (wantOptDielectric) file << ",dimensionless";
        if (wantRefLoss) file << ",dimensionless";
        if (wantMolarRef) file << ",cm3/mol";
        if (wantMetallization) file << ",dimensionless";
        if (wantMolarPolar) file << ",Å3";
        if (wantElectronicPolar) file << ",Å3";
        if (wantOptTrans) file << ",dimensionless";
        if (wantOptElectroneg) file << ",dimensionless";
        if (wantLinearSuscept) file << ",dimensionless";
        if (wantNonlinearSuscept) file << ",10^-16 esu";
        if (wantNonlinearRefIndex) file << ",10^-15 esu";
    }
    file << "\n";
    
    // Row 3: Comments (Empty)
    file << "\n";
    std::map<string, BulkProperties> bpMap;
    for (const auto& cd : compsData) {
        string effectiveDopant = cd.dopantIon.empty() ? targetIon : cd.dopantIon;
        bpMap[cd.formula] = calculateBulkProperties(cd.formula, cd.density, db, effectiveDopant, cd.bandGap, cd.cn);
    }

    // Row 4+: Data
    for (double e : allEnergies) {
        file << e;
        if (hasIsotopes) {
            auto it = energyToIsotope.find(e);
            file << "," << (it != energyToIsotope.end() ? it->second : "");
        }
        
        for (const auto& cd : compsData) {
            // Find index of energy e in cd.mac
            int idx = -1;
            for (size_t j = 0; j < cd.mac.size(); j++) {
                if (abs(cd.mac[j].energy - e) < 1e-9) {
                    idx = j;
                    break;
                }
            }
            
            if (idx != -1) {
                if (wantMAC) file << "," << cd.mac[idx].mac;
                if (wantLAC) file << "," << (idx < cd.lac.size() ? cd.lac[idx].mac : 0.0);
                if (wantMFP) file << "," << (idx < cd.mfp.size() ? cd.mfp[idx].mac : 0.0);
                if (wantHVL) file << "," << (idx < cd.hvl.size() ? cd.hvl[idx].mac : 0.0);
                if (wantTVL) file << "," << (idx < cd.tvl.size() ? cd.tvl[idx].mac : 0.0);
                if (wantZeff) file << "," << (idx < cd.zeff.size() ? cd.zeff[idx].mac : 0.0);
                if (wantNe) file << "," << (idx < cd.ne.size() ? cd.ne[idx].mac : 0.0);
                
                if (wantTF) for (double t : t_values) file << "," << cd.tfMap.at(t)[idx].mac;
                if (wantRPE) for (double t : t_values) file << "," << cd.rpeMap.at(t)[idx].mac;
                if (wantLeq) for (double t : t_values) file << "," << cd.leqMap.at(t)[idx].mac;
                
                if (hasZeq) {
                    int zeq_idx = -1;
                    for (size_t j = 0; j < cd.zeq.size(); j++) {
                        if (abs(cd.zeq[j].energy - e) < 1e-9) {
                            zeq_idx = j;
                            break;
                        }
                    }
                    if (zeq_idx != -1) {
                        file << "," << cd.zeq[zeq_idx].zeq 
                             << "," << cd.gp[zeq_idx].absorption.b << "," << cd.gp[zeq_idx].absorption.c << "," << cd.gp[zeq_idx].absorption.a << "," << cd.gp[zeq_idx].absorption.Xk << "," << cd.gp[zeq_idx].absorption.d
                             << "," << cd.gp[zeq_idx].exposure.b << "," << cd.gp[zeq_idx].exposure.c << "," << cd.gp[zeq_idx].exposure.a << "," << cd.gp[zeq_idx].exposure.Xk << "," << cd.gp[zeq_idx].exposure.d;
                    } else {
                        file << ",,,,,,,,,,,";
                    }
                }
                
                if (params.count("ebf") || params.count("eabf")) {
                    int bu_idx = -1;
                    for (size_t j = 0; j < cd.bu.size(); j++) {
                        if (abs(cd.bu[j].energy - e) < 1e-9) {
                            bu_idx = j;
                            break;
                        }
                    }
                    if (bu_idx != -1) {
                        if (params.count("ebf")) for (double val : cd.bu[bu_idx].ebf) file << "," << val;
                        if (params.count("eabf")) for (double val : cd.bu[bu_idx].eabf) file << "," << val;
                    } else {
                        if (params.count("ebf")) for (size_t j=0; j<x_mfp.size(); j++) file << ",";
                        if (params.count("eabf")) for (size_t j=0; j<x_mfp.size(); j++) file << ",";
                    }
                }
            } else {
                // Not found in this composition, write empty columns
                if (wantMAC) file << ",";
                if (wantLAC) file << ",";
                if (wantMFP) file << ",";
                if (wantHVL) file << ",";
                if (wantTVL) file << ",";
                if (wantZeff) file << ",";
                if (wantNe) file << ",";
                if (wantTF) for (size_t j=0; j<t_values.size(); j++) file << ",";
                if (wantRPE) for (size_t j=0; j<t_values.size(); j++) file << ",";
                if (wantLeq) for (size_t j=0; j<t_values.size(); j++) file << ",";
                if (hasZeq) file << ",,,,,,,,,,,";
                if (params.count("ebf")) for (size_t j=0; j<x_mfp.size(); j++) file << ",";
                if (params.count("eabf")) for (size_t j=0; j<x_mfp.size(); j++) file << ",";
            }

            bool isMechAvail = isCompositionAvailableInMechanicalDB(cd.formula);
            BulkProperties bp = bpMap[cd.formula];
            if (wantMolarMass) file << "," << bp.molarMass;
            if (wantDensity) file << "," << cd.density;
            if (wantCN) file << "," << (cd.cn.empty() ? "N/A" : cd.cn);
            if (wantBandgap) file << "," << (cd.bandGap > 0 ? std::to_string(cd.bandGap) : "N/A");
            if (wantDopant) file << "," << (cd.dopantIon.empty() ? "N/A" : cd.dopantIon);
            if (wantMolarVol) file << "," << bp.molarVolume;
            if (wantAvgBoron) file << "," << (bp.avgBoronDistance > 0.0 ? to_string(bp.avgBoronDistance) : "N/A");
            if (wantOPD) file << "," << bp.oxygenPackingDensity;
            if (wantOxygenVol) file << "," << bp.oxygenMolarVolume;
            if (wantIonConc) file << "," << bp.ionConcentration;
            if (wantInterIonic) file << "," << bp.interIonicDistance;
            if (wantPolaron) file << "," << bp.polaronRadius;
            if (wantFieldStrength) file << "," << bp.fieldStrength;
            
            if (wantPackingDensity) file << "," << (isMechAvail ? to_string(bp.packingDensity) : "compound is not available in database(MECHANICAL)");
            if (wantDissEnergy) file << "," << (isMechAvail ? to_string(bp.dissociationEnergy) : "compound is not available in database(MECHANICAL)");
            if (wantYoung) file << "," << (isMechAvail ? to_string(bp.youngsModulus) : "compound is not available in database(MECHANICAL)");
            if (wantBulk) file << "," << (isMechAvail ? to_string(bp.bulkModulus) : "compound is not available in database(MECHANICAL)");
            if (wantShear) file << "," << (isMechAvail ? to_string(bp.shearModulus) : "compound is not available in database(MECHANICAL)");
            if (wantLong) file << "," << (isMechAvail ? to_string(bp.longitudinalModulus) : "compound is not available in database(MECHANICAL)");
            if (wantPoisson) file << "," << (isMechAvail ? to_string(bp.poissonsRatio) : "compound is not available in database(MECHANICAL)");
            if (wantHardness) file << "," << (isMechAvail ? to_string(bp.hardness) : "compound is not available in database(MECHANICAL)");
            if (wantFractal) file << "," << (isMechAvail ? to_string(bp.fractalBondConnectivity) : "compound is not available in database(MECHANICAL)");
            
            if (wantRefIndex) file << "," << bp.refractiveIndex;
            if (wantDielectric) file << "," << bp.dielectricConstant;
            if (wantOptDielectric) file << "," << bp.optDielectricConstant;
            if (wantRefLoss) file << "," << bp.reflectionLoss;
            if (wantMolarRef) file << "," << bp.molarRefractivity;
            if (wantMetallization) file << "," << bp.metallization;
            if (wantMolarPolar) file << "," << bp.molarPolarizability;
            if (wantElectronicPolar) file << "," << bp.electronicPolarizability;
            if (wantOptTrans) file << "," << bp.transmissionCoefficient;
            if (wantOptElectroneg) file << "," << bp.optElectronegativity;
            if (wantLinearSuscept) file << "," << bp.linearSusceptibility;
            if (wantNonlinearSuscept) file << "," << bp.nonlinearSusceptibility;
            if (wantNonlinearRefIndex) file << "," << bp.nonlinearRefractiveIndex;
        }
        file << "\n";
    }

    if (returnStringOnly) {
        return file.str();
    }
    
    string sanitized = materialName;
    for (char &c : sanitized) {
        if (c == '\\' || c == '/' || c == ':' || c == '*' || c == '?' || c == '"' || c == '<' || c == '>' || c == '|') c = '_';
        if (c == ' ') c = '_';
    }
    if (sanitized.empty()) sanitized = "default";
    string filename = "Shielding_Analysis_" + sanitized + "_Origin.csv";

    ofstream out(filename);
    if (!out.is_open()) return "";
    out << file.str();
    out.close();
    return filename;
}

string exportFullAnalysisToOriginCSV(
    string materialName, string mixture, double density, const vector<double>& t_values,
    const vector<double>& x_mfp, 
    const vector<AttenuationResult>& macData, 
    const vector<AttenuationResult>& lacData,
    const vector<AttenuationResult>& mfpData,
    const vector<AttenuationResult>& hvlData,
    const vector<AttenuationResult>& tvlData,
    const vector<AttenuationResult>& zeffData,
    const vector<AttenuationResult>& neData,
    const map<double, vector<AttenuationResult>>& tfMap,
    const map<double, vector<AttenuationResult>>& rpeMap,
    const map<double, vector<AttenuationResult>>& leqMap,
    const vector<ZeqResult>& zeqData, 
    const vector<GPResult>& gpData, 
    const vector<BuildUpRow>& buData,
    const set<string>& params,
    const map<double, string>& energyToIsotope,
    bool returnStringOnly,
    PeriodicDatabase& db,
    const string& targetIon = "",
    double eg = 0.0,
    const string& cnStr = "") 
{
    string sanitized = mixture;
    for (char &c : sanitized) if (c == ' ' || c == '+' || c == '.' || c == '(' || c == ')') c = '_';

    if (sanitized.length() > 60) sanitized = sanitized.substr(0, 60);
    sanitized += "_" + to_string(rand());

    string filename;
    if (!materialName.empty()) {
        string sanitizedMatName = materialName;
        for (char &c : sanitizedMatName) {
            if (c == '\\' || c == '/' || c == ':' || c == '*' || c == '?' || c == '"' || c == '<' || c == '>' || c == '|') c = '_';
            if (c == ' ') c = '_';
        }
        if (sanitizedMatName.length() > 30) sanitizedMatName = sanitizedMatName.substr(0, 30);
        filename = sanitizedMatName + "_" + sanitized + "_Origin.csv";
    } else {
        filename = "Shielding_Analysis_" + sanitized + "_Origin.csv";
    }

    ostringstream file;

    bool hasIsotopes = !energyToIsotope.empty();
    bool wantMAC  = params.count("mac");
    bool wantLAC  = params.count("lac");
    bool wantMFP  = params.count("mfp");
    bool wantHVL  = params.count("hvl");
    bool wantTVL  = params.count("tvl");
    bool wantZeff = params.count("zeff");
    bool wantNe   = params.count("ne");
    bool wantTF   = params.count("tf");
    bool wantRPE  = params.count("rpe");
    bool wantLeq  = params.count("leq");
    bool hasZeq = params.count("zeq") || params.count("gp") || params.count("ebf") || params.count("eabf");

    bool wantMolarMass = params.count("molar_mass");
    bool wantMolarVol = params.count("molar_vol");
    bool wantAvgBoron = params.count("p-dB_B");
    bool wantOPD = params.count("opd");
    bool wantOxygenVol = params.count("o_molar_vol");
    bool wantIonConc = params.count("ion-conc");
    bool wantInterIonic = params.count("inter_ionic_dist");
    bool wantPolaron = params.count("polaron_radius");
    bool wantFieldStrength = params.count("field_strength");
    
    bool wantPackingDensity = params.count("packing_density");
    bool wantDissEnergy = params.count("dissociation_energy");
    bool wantYoung = params.count("youngs_modulus");
    bool wantBulk = params.count("bulk_modulus");
    bool wantShear = params.count("shear_modulus");
    bool wantLong = params.count("longitudinal_modulus");
    bool wantPoisson = params.count("poissons_ratio");
    bool wantHardness = params.count("hardness");
    bool wantFractal = params.count("fractalbondconnectivity");
    
    bool wantRefIndex = params.count("refractive_index");
    bool wantDielectric = params.count("dielectric_constant");
    bool wantOptDielectric = params.count("opt_dielectric_constant");
    bool wantRefLoss = params.count("reflection_loss");
    bool wantMolarRef = params.count("molar_refractivity");
    bool wantMetallization = params.count("metallization");
    bool wantMolarPolar = params.count("molar_polarizability");
    bool wantElectronicPolar = params.count("electronic_polarizability");
    bool wantOptTrans = params.count("optical_transmission");
    bool wantOptElectroneg = params.count("opt_electronegativity");
    bool wantLinearSuscept = params.count("linear_susceptibility");
    bool wantNonlinearSuscept = params.count("nonlinear_susceptibility");
    bool wantNonlinearRefIndex = params.count("nonlinear_refractive_index");

    bool wantDensity = params.count("density_output") || wantLAC || wantMFP || wantHVL || wantTVL || wantTF || wantRPE || wantLeq || wantMolarVol || wantOPD || wantOxygenVol || wantIonConc || wantInterIonic || wantPolaron || wantFieldStrength || wantPackingDensity || wantDissEnergy || wantYoung || wantBulk || wantShear || wantLong || wantPoisson || wantHardness || wantFractal || wantMolarRef || wantMetallization || wantMolarPolar || wantElectronicPolar || wantOptTrans || wantLinearSuscept || wantNonlinearSuscept || wantNonlinearRefIndex;
    bool wantBandgap = params.count("bandgap_output") || wantRefIndex || wantDielectric || wantOptDielectric || wantRefLoss || wantMolarRef || wantMetallization || wantMolarPolar || wantElectronicPolar || wantOptTrans || wantOptElectroneg || wantLinearSuscept || wantNonlinearSuscept || wantNonlinearRefIndex;
    bool wantCN = wantPackingDensity || wantDissEnergy || wantYoung || wantBulk || wantShear || wantLong || wantPoisson || wantHardness || wantFractal;
    bool wantDopant = wantIonConc || wantInterIonic || wantPolaron || wantFieldStrength;

    // Row 1: Long Name
    file << "Energy";
    if (hasIsotopes) file << ",Isotope";
    if (wantMAC) file << ",MAC";
    if (wantLAC) file << ",LAC";
    if (wantMFP) file << ",MFP";
    if (wantHVL) file << ",HVL";
    if (wantTVL) file << ",TVL";
    if (wantZeff) file << ",Zeff";
    if (wantNe) file << ",Ne";
    if (wantTF) for (double t : t_values) file << ",TF (t=" << t << ")";
    if (wantRPE) for (double t : t_values) file << ",RPE (t=" << t << ")";
    if (wantLeq) for (double t : t_values) file << ",Leq (t=" << t << ")";
    if (hasZeq) file << ",Zeq,GP_Abs_b,GP_Abs_c,GP_Abs_a,GP_Abs_Xk,GP_Abs_d,GP_Exp_b,GP_Exp_c,GP_Exp_a,GP_Exp_Xk,GP_Exp_d";
    if (params.count("ebf")) for (double x : x_mfp) file << ",EBF (x=" << x << ")";
    if (params.count("eabf")) for (double x : x_mfp) file << ",EABF (x=" << x << ")";

    if (wantMolarMass) file << ",Molar Mass";
    if (wantDensity) file << ",Density";
    if (wantCN) file << ",CN";
    if (wantBandgap) file << ",Bandgap";
    if (wantDopant) file << ",Dopant";
    if (wantMolarVol) file << ",Molar Volume";
    if (wantAvgBoron) file << ",Avg Boron Distance";
    if (wantOPD) file << ",Oxygen Packing Density";
    if (wantOxygenVol) file << ",Oxygen Molar Volume";
    if (wantIonConc) file << ",Ion Concentration";
    if (wantInterIonic) file << ",Inter-ionic Distance";
    if (wantPolaron) file << ",Polaron Radius";
    if (wantFieldStrength) file << ",Field Strength";
    if (wantPackingDensity) file << ",Packing Density";
    if (wantDissEnergy) file << ",Dissociation Energy";
    if (wantYoung) file << ",Youngs Modulus";
    if (wantBulk) file << ",Bulk Modulus";
    if (wantShear) file << ",Shear Modulus";
    if (wantLong) file << ",Longitudinal Modulus";
    if (wantPoisson) file << ",Poissons Ratio";
    if (wantHardness) file << ",Vickers Hardness";
    if (wantFractal) file << ",Fractal Bond Connectivity";
    if (wantRefIndex) file << ",Refractive Index";
    if (wantDielectric) file << ",Dielectric Constant";
    if (wantOptDielectric) file << ",Optical Dielectric Constant";
    if (wantRefLoss) file << ",Reflection Loss";
    if (wantMolarRef) file << ",Molar Refractivity";
    if (wantMetallization) file << ",Metallization Criterion";
    if (wantMolarPolar) file << ",Molar Polarizability";
    if (wantElectronicPolar) file << ",Electronic Polarizability";
    if (wantOptTrans) file << ",Transmission Coefficient";
    if (wantOptElectroneg) file << ",Optical Electronegativity";
    if (wantLinearSuscept) file << ",Linear Susceptibility";
    if (wantNonlinearSuscept) file << ",Non-linear Susceptibility";
    if (wantNonlinearRefIndex) file << ",Non-linear Refractive Index";
    file << "\n";
    
    // Row 2: Units
    file << "MeV";
    if (hasIsotopes) file << ",";
    if (wantMAC) file << ",cm2/g";
    if (wantLAC) file << ",cm-1";
    if (wantMFP) file << ",cm";
    if (wantHVL) file << ",cm";
    if (wantTVL) file << ",cm";
    if (wantZeff) file << ",";
    if (wantNe) file << ",electrons/g";
    if (wantTF) for (size_t i=0; i<t_values.size(); i++) file << ",%";
    if (wantRPE) for (size_t i=0; i<t_values.size(); i++) file << ",%";
    if (wantLeq) for (size_t i=0; i<t_values.size(); i++) file << ",cm";
    if (hasZeq) file << ",,,,,,,,,,,";
    if (params.count("ebf")) for (size_t i=0; i<x_mfp.size(); i++) file << ",";
    if (params.count("eabf")) for (size_t i=0; i<x_mfp.size(); i++) file << ",";

    if (wantMolarMass) file << ",g/mol";
    if (wantDensity) file << ",g/cm3";
    if (wantCN) file << ",";
    if (wantBandgap) file << ",eV";
    if (wantDopant) file << ",";
    if (wantMolarVol) file << ",cm3/mol";
    if (wantAvgBoron) file << ",10^-8 cm";
    if (wantOPD) file << ",g-atom/L";
    if (wantOxygenVol) file << ",cm3/mol";
    if (wantIonConc) file << ",10^21 ions/cm3";
    if (wantInterIonic) file << ",10^-8 cm";
    if (wantPolaron) file << ",10^-8 cm";
    if (wantFieldStrength) file << ",10^15 cm-2";
    if (wantPackingDensity) file << ",dimensionless";
    if (wantDissEnergy) file << ",kJ/cm3";
    if (wantYoung) file << ",GPa";
    if (wantBulk) file << ",GPa";
    if (wantShear) file << ",GPa";
    if (wantLong) file << ",GPa";
    if (wantPoisson) file << ",dimensionless";
    if (wantHardness) file << ",GPa";
    if (wantFractal) file << ",dimensionless";
    if (wantRefIndex) file << ",dimensionless";
    if (wantDielectric) file << ",dimensionless";
    if (wantOptDielectric) file << ",dimensionless";
    if (wantRefLoss) file << ",dimensionless";
    if (wantMolarRef) file << ",cm3/mol";
    if (wantMetallization) file << ",dimensionless";
    if (wantMolarPolar) file << ",Å3";
    if (wantElectronicPolar) file << ",Å3";
    if (wantOptTrans) file << ",dimensionless";
    if (wantOptElectroneg) file << ",dimensionless";
    if (wantLinearSuscept) file << ",dimensionless";
    if (wantNonlinearSuscept) file << ",10^-16 esu";
    if (wantNonlinearRefIndex) file << ",10^-15 esu";
    file << "\n";
        BulkProperties bp = calculateBulkProperties(mixture, density, db, targetIon, eg, cnStr);

    // Row 4+: Data
    for (size_t i = 0; i < macData.size(); i++) {
        double e = macData[i].energy;
        file << e;
        if (hasIsotopes) {
            auto it = energyToIsotope.find(e);
            file << "," << (it != energyToIsotope.end() ? it->second : "");
        }
        if (wantMAC) file << "," << macData[i].mac;
        if (wantLAC && i < lacData.size()) file << "," << lacData[i].mac;
        if (wantMFP && i < mfpData.size()) file << "," << mfpData[i].mac;
        if (wantHVL && i < hvlData.size()) file << "," << hvlData[i].mac;
        if (wantTVL && i < tvlData.size()) file << "," << tvlData[i].mac;
        if (wantZeff && i < zeffData.size()) file << "," << zeffData[i].mac;
        if (wantNe && i < neData.size()) file << "," << neData[i].mac;
        
        if (wantTF) for (double t : t_values) file << "," << tfMap.at(t)[i].mac;
        if (wantRPE) for (double t : t_values) file << "," << rpeMap.at(t)[i].mac;
        if (wantLeq) for (double t : t_values) file << "," << leqMap.at(t)[i].mac;
        
        if (hasZeq) {
            int zeq_idx = -1;
            for (size_t j = 0; j < zeqData.size(); j++) {
                if (abs(zeqData[j].energy - e) < 1e-9) {
                    zeq_idx = j;
                    break;
                }
            }
            if (zeq_idx != -1) {
                file << "," << zeqData[zeq_idx].zeq 
                     << "," << gpData[zeq_idx].absorption.b << "," << gpData[zeq_idx].absorption.c << "," << gpData[zeq_idx].absorption.a << "," << gpData[zeq_idx].absorption.Xk << "," << gpData[zeq_idx].absorption.d
                     << "," << gpData[zeq_idx].exposure.b << "," << gpData[zeq_idx].exposure.c << "," << gpData[zeq_idx].exposure.a << "," << gpData[zeq_idx].exposure.Xk << "," << gpData[zeq_idx].exposure.d;
            } else {
                file << ",,,,,,,,,,,";
            }
        }
        
        if (params.count("ebf") || params.count("eabf")) {
            int bu_idx = -1;
            for (size_t j = 0; j < buData.size(); j++) {
                if (abs(buData[j].energy - e) < 1e-9) {
                    bu_idx = j;
                    break;
                }
            }
            if (bu_idx != -1) {
                if (params.count("ebf")) for (double val : buData[bu_idx].ebf) file << "," << val;
                if (params.count("eabf")) for (double val : buData[bu_idx].eabf) file << "," << val;
            } else {
                if (params.count("ebf")) for (size_t j=0; j<x_mfp.size(); j++) file << ",";
                if (params.count("eabf")) for (size_t j=0; j<x_mfp.size(); j++) file << ",";
            }
        }

        bool isMechAvail = isCompositionAvailableInMechanicalDB(mixture);
        if (wantMolarMass) file << "," << bp.molarMass;
        if (wantDensity) file << "," << density;
        if (wantCN) file << "," << (cnStr.empty() ? "N/A" : cnStr);
        if (wantBandgap) file << "," << (eg > 0 ? std::to_string(eg) : "N/A");
        if (wantDopant) file << "," << (targetIon.empty() ? "N/A" : targetIon);
        if (wantMolarVol) file << "," << bp.molarVolume;
        if (wantAvgBoron) file << "," << (bp.avgBoronDistance > 0.0 ? to_string(bp.avgBoronDistance) : "N/A");
        if (wantOPD) file << "," << bp.oxygenPackingDensity;
        if (wantOxygenVol) file << "," << bp.oxygenMolarVolume;
        if (wantIonConc) file << "," << bp.ionConcentration;
        if (wantInterIonic) file << "," << bp.interIonicDistance;
        if (wantPolaron) file << "," << bp.polaronRadius;
        if (wantFieldStrength) file << "," << bp.fieldStrength;
        
        if (wantPackingDensity) file << "," << (isMechAvail ? to_string(bp.packingDensity) : "compound is not available in database(MECHANICAL)");
        if (wantDissEnergy) file << "," << (isMechAvail ? to_string(bp.dissociationEnergy) : "compound is not available in database(MECHANICAL)");
        if (wantYoung) file << "," << (isMechAvail ? to_string(bp.youngsModulus) : "compound is not available in database(MECHANICAL)");
        if (wantBulk) file << "," << (isMechAvail ? to_string(bp.bulkModulus) : "compound is not available in database(MECHANICAL)");
        if (wantShear) file << "," << (isMechAvail ? to_string(bp.shearModulus) : "compound is not available in database(MECHANICAL)");
        if (wantLong) file << "," << (isMechAvail ? to_string(bp.longitudinalModulus) : "compound is not available in database(MECHANICAL)");
        if (wantPoisson) file << "," << (isMechAvail ? to_string(bp.poissonsRatio) : "compound is not available in database(MECHANICAL)");
        if (wantHardness) file << "," << (isMechAvail ? to_string(bp.hardness) : "compound is not available in database(MECHANICAL)");
        if (wantFractal) file << "," << (isMechAvail ? to_string(bp.fractalBondConnectivity) : "compound is not available in database(MECHANICAL)");
        
        if (wantRefIndex) file << "," << bp.refractiveIndex;
        if (wantDielectric) file << "," << bp.dielectricConstant;
        if (wantOptDielectric) file << "," << bp.optDielectricConstant;
        if (wantRefLoss) file << "," << bp.reflectionLoss;
        if (wantMolarRef) file << "," << bp.molarRefractivity;
        if (wantMetallization) file << "," << bp.metallization;
        if (wantMolarPolar) file << "," << bp.molarPolarizability;
        if (wantElectronicPolar) file << "," << bp.electronicPolarizability;
        if (wantOptTrans) file << "," << bp.transmissionCoefficient;
        if (wantOptElectroneg) file << "," << bp.optElectronegativity;
        if (wantLinearSuscept) file << "," << bp.linearSusceptibility;
        if (wantNonlinearSuscept) file << "," << bp.nonlinearSusceptibility;
        if (wantNonlinearRefIndex) file << "," << bp.nonlinearRefractiveIndex;
        
        file << "\n";
    }

    if (returnStringOnly) {
        return file.str();
    }
    
    ofstream out(filename);
    if (!out.is_open()) return "";
    out << file.str();
    out.close();
    return filename;
}

string exportFullAnalysisToExcel(
    string materialName, string mixture, double density, const vector<double>& t_values,
    const vector<MoleFractionResult>& moleData,
    const vector<double>& x_mfp, 
    const vector<AttenuationResult>& macData, 
    const vector<AttenuationResult>& lacData,
    const vector<AttenuationResult>& mfpData,
    const vector<AttenuationResult>& hvlData,
    const vector<AttenuationResult>& tvlData,
    const vector<AttenuationResult>& zeffData,
    const vector<AttenuationResult>& neData,
    const map<double, vector<AttenuationResult>>& tfMap,
    const map<double, vector<AttenuationResult>>& rpeMap,
    const map<double, vector<AttenuationResult>>& leqMap,
    const vector<ZeqResult>& zeqData, 
    const vector<GPResult>& gpData, 
    const vector<BuildUpRow>& buData,
    const set<string>& params,
    const map<double, string>& energyToIsotope,
    PeriodicDatabase& db,
    const string& targetIon = "",
    double eg = 0.0,
    const string& cnStr = "") 
{
    // Construct unique filename
    string sanitized = mixture;
    for (char &c : sanitized) if (c == ' ' || c == '+' || c == '.' || c == '(' || c == ')') c = '_';

    if (sanitized.length() > 60) sanitized = sanitized.substr(0, 60);
    sanitized += "_" + to_string(rand());

    string filename;
    if (!materialName.empty()) {
        string sanitizedMatName = materialName;
        // Strip invalid characters for windows filenames
        for (char &c : sanitizedMatName) {
            if (c == '\\' || c == '/' || c == ':' || c == '*' || c == '?' || c == '"' || c == '<' || c == '>' || c == '|') c = '_';
            if (c == ' ') c = '_';
        }
        if (sanitizedMatName.length() > 30) sanitizedMatName = sanitizedMatName.substr(0, 30);
        filename = sanitizedMatName + "_" + sanitized + ".xls";
    } else {
        filename = "Shielding_Analysis_" + sanitized + ".xls";
    }

    ofstream file(filename);
    if (!file.is_open()) return "";

    bool hasIsotopes = !energyToIsotope.empty();
    bool wantMAC  = params.count("mac");
    bool wantLAC  = params.count("lac");
    bool wantMFP  = params.count("mfp");
    bool wantHVL  = params.count("hvl");
    bool wantTVL  = params.count("tvl");
    bool wantZeff = params.count("zeff");
    bool wantNe   = params.count("ne");
    bool wantTF   = params.count("tf");
    bool wantRPE  = params.count("rpe");
    bool wantLeq  = params.count("leq");
    bool wantZeq  = params.count("zeq");
    bool wantGP   = params.count("gp");
    bool wantEBF  = params.count("ebf");
    bool wantEABF = params.count("eabf");
    bool wantMole = params.count("mole");
    bool wantInteraction = wantMAC || wantLAC || wantMFP || wantHVL || wantTVL || wantZeff || wantNe;

    file << "<?xml version=\"1.0\"?>\n<?mso-application progid=\"Excel.Sheet\"?>\n";
    file << "<Workbook xmlns=\"urn:schemas-microsoft-com:office:spreadsheet\"\n";
    file << " xmlns:o=\"urn:schemas-microsoft-com:office:office\"\n xmlns:x=\"urn:schemas-microsoft-com:office:excel\"\n";
    file << " xmlns:ss=\"urn:schemas-microsoft-com:office:spreadsheet\">\n";

    // --- SHEET 1: SUMMARY ---
    file << " <Worksheet ss:Name=\"Summary\">\n <Table>\n";
    file << "  <Row><Cell><Data ss:Type=\"String\">Mixture</Data></Cell><Cell><Data ss:Type=\"String\">" << mixture << "</Data></Cell></Row>\n";
    file << "  <Row><Cell><Data ss:Type=\"String\">Density (g/cm3)</Data></Cell><Cell><Data ss:Type=\"Number\">" << density << "</Data></Cell></Row>\n";
    
    // List all thicknesses clearly
    if (!t_values.empty()) {
        file << "  <Row><Cell><Data ss:Type=\"String\">Thicknesses (cm)</Data></Cell><Cell><Data ss:Type=\"String\">";
        for(size_t i=0; i<t_values.size(); ++i) file << t_values[i] << (i == t_values.size()-1 ? "" : ", ");
        file << "</Data></Cell></Row>\n";
    }

    file << "  <Row><Cell ss:Index=\"1\"/><Cell/></Row>\n";
    if (wantMole) {
        file << "  <Row><Cell><Data ss:Type=\"String\">Element</Data></Cell><Cell><Data ss:Type=\"String\">Weight Fraction</Data></Cell><Cell><Data ss:Type=\"String\">Mole Fraction</Data></Cell></Row>\n";
        for(const auto& m : moleData) {
            file << "  <Row><Cell><Data ss:Type=\"String\">" << m.symbol << "</Data></Cell>";
            file << "<Cell><Data ss:Type=\"Number\">" << m.weightFraction << "</Data></Cell>";
            file << "<Cell><Data ss:Type=\"Number\">" << m.moleFraction << "</Data></Cell></Row>\n";
        }
    }

    if (!x_mfp.empty()) {
        file << "  <Row><Cell><Data ss:Type=\"String\">Depths (mfp)</Data></Cell><Cell><Data ss:Type=\"String\">";
        for(double x : x_mfp) file << x << " ";
        file << "</Data></Cell></Row>\n";
    }

    bool wantPhysical = params.count("molar_mass") || params.count("molar_vol") || params.count("p-dB_B") || 
                        params.count("opd") || params.count("o_molar_vol") || params.count("ion-conc") || 
                        params.count("inter_ionic_dist") || params.count("polaron_radius") || params.count("field_strength");
    bool wantMechanical = params.count("youngs_modulus") || params.count("bulk_modulus") || params.count("shear_modulus") || 
                          params.count("longitudinal_modulus") || params.count("poissons_ratio") || params.count("hardness") || 
                          params.count("packing_density") || params.count("dissociation_energy") || params.count("fractalbondconnectivity");
    bool wantOptical = params.count("refractive_index") || params.count("molar_refractivity") || params.count("molar_polarizability") || 
                       params.count("metallization") || params.count("reflection_loss") || params.count("optical_transmission") ||
                       params.count("dielectric_constant") || params.count("opt_dielectric_constant") ||
                       params.count("electronic_polarizability") || params.count("opt_electronegativity") ||
                       params.count("linear_susceptibility") || params.count("nonlinear_susceptibility") ||
                       params.count("nonlinear_refractive_index");

    if (wantPhysical || wantMechanical || wantOptical) {
        file << "  <Row><Cell ss:Index=\"1\"/><Cell/></Row>\n";
        BulkProperties bp = calculateBulkProperties(mixture, density, db, targetIon, eg, cnStr);
        
        if (wantPhysical) {
            file << "  <Row><Cell><Data ss:Type=\"String\">--- Physical Properties ---</Data></Cell><Cell/><Cell/></Row>\n";
            if (params.count("molar_mass")) {
                file << "  <Row><Cell><Data ss:Type=\"String\">Molar Mass</Data></Cell>";
                writeSafeCell(file, bp.molarMass);
                file << "<Cell><Data ss:Type=\"String\">g/mol</Data></Cell></Row>\n";
            }
            if (params.count("molar_vol")) {
                file << "  <Row><Cell><Data ss:Type=\"String\">Molar Volume</Data></Cell>";
                writeSafeCell(file, bp.molarVolume);
                file << "<Cell><Data ss:Type=\"String\">cm3/mol</Data></Cell></Row>\n";
            }
            if (params.count("p-dB_B")) {
                file << "  <Row><Cell><Data ss:Type=\"String\">Avg. Distance Between Boron Atoms</Data></Cell>";
                if (bp.avgBoronDistance > 0.0) writeSafeCell(file, bp.avgBoronDistance);
                else file << "   <Cell><Data ss:Type=\"String\">N/A</Data></Cell>\n";
                file << "<Cell><Data ss:Type=\"String\">10^-8 cm</Data></Cell></Row>\n";
            }
            if (params.count("opd")) {
                file << "  <Row><Cell><Data ss:Type=\"String\">Oxygen Packing Density</Data></Cell>";
                writeSafeCell(file, bp.oxygenPackingDensity);
                file << "<Cell><Data ss:Type=\"String\">g-atom/L</Data></Cell></Row>\n";
            }
            if (params.count("o_molar_vol")) {
                file << "  <Row><Cell><Data ss:Type=\"String\">Oxygen Molar Volume</Data></Cell>";
                writeSafeCell(file, bp.oxygenMolarVolume);
                file << "<Cell><Data ss:Type=\"String\">cm3/mol</Data></Cell></Row>\n";
            }
            if (params.count("ion-conc")) {
                file << "  <Row><Cell><Data ss:Type=\"String\">Cation Ion Concentration</Data></Cell>";
                writeSafeCell(file, bp.ionConcentration);
                file << "<Cell><Data ss:Type=\"String\">10^21 ions/cm3</Data></Cell></Row>\n";
            }
            if (params.count("inter_ionic_dist")) {
                file << "  <Row><Cell><Data ss:Type=\"String\">Inter-ionic Distance</Data></Cell>";
                writeSafeCell(file, bp.interIonicDistance);
                file << "<Cell><Data ss:Type=\"String\">10^-8 cm</Data></Cell></Row>\n";
            }
            if (params.count("polaron_radius")) {
                file << "  <Row><Cell><Data ss:Type=\"String\">Polaron Radius</Data></Cell>";
                writeSafeCell(file, bp.polaronRadius);
                file << "<Cell><Data ss:Type=\"String\">10^-8 cm</Data></Cell></Row>\n";
            }
            if (params.count("field_strength")) {
                file << "  <Row><Cell><Data ss:Type=\"String\">Field Strength</Data></Cell>";
                writeSafeCell(file, bp.fieldStrength);
                file << "<Cell><Data ss:Type=\"String\">10^15 cm-2</Data></Cell></Row>\n";
            }
        }
        
        if (wantMechanical) {
            file << "  <Row><Cell><Data ss:Type=\"String\">--- Mechanical Properties (Makishima-Mackenzie Model) ---</Data></Cell><Cell/><Cell/></Row>\n";
            bool isMechAvail = isCompositionAvailableInMechanicalDB(mixture);
            if (params.count("packing_density")) {
                file << "  <Row><Cell><Data ss:Type=\"String\">Packing Density (Vt)</Data></Cell>";
                if (isMechAvail) writeSafeCell(file, bp.packingDensity);
                else file << "<Cell><Data ss:Type=\"String\">compound is not available in database(MECHANICAL)</Data></Cell>";
                file << "<Cell><Data ss:Type=\"String\">dimensionless</Data></Cell></Row>\n";
            }
            if (params.count("dissociation_energy")) {
                file << "  <Row><Cell><Data ss:Type=\"String\">Dissociation Energy (Gt)</Data></Cell>";
                if (isMechAvail) writeSafeCell(file, bp.dissociationEnergy);
                else file << "<Cell><Data ss:Type=\"String\">compound is not available in database(MECHANICAL)</Data></Cell>";
                file << "<Cell><Data ss:Type=\"String\">kJ/cm3</Data></Cell></Row>\n";
            }
            if (params.count("youngs_modulus")) {
                file << "  <Row><Cell><Data ss:Type=\"String\">Young's Modulus</Data></Cell>";
                if (isMechAvail) writeSafeCell(file, bp.youngsModulus);
                else file << "<Cell><Data ss:Type=\"String\">compound is not available in database(MECHANICAL)</Data></Cell>";
                file << "<Cell><Data ss:Type=\"String\">GPa</Data></Cell></Row>\n";
            }
            if (params.count("bulk_modulus")) {
                file << "  <Row><Cell><Data ss:Type=\"String\">Bulk Modulus</Data></Cell>";
                if (isMechAvail) writeSafeCell(file, bp.bulkModulus);
                else file << "<Cell><Data ss:Type=\"String\">compound is not available in database(MECHANICAL)</Data></Cell>";
                file << "<Cell><Data ss:Type=\"String\">GPa</Data></Cell></Row>\n";
            }
            if (params.count("shear_modulus")) {
                file << "  <Row><Cell><Data ss:Type=\"String\">Shear Modulus</Data></Cell>";
                if (isMechAvail) writeSafeCell(file, bp.shearModulus);
                else file << "<Cell><Data ss:Type=\"String\">compound is not available in database(MECHANICAL)</Data></Cell>";
                file << "<Cell><Data ss:Type=\"String\">GPa</Data></Cell></Row>\n";
            }
            if (params.count("longitudinal_modulus")) {
                file << "  <Row><Cell><Data ss:Type=\"String\">Longitudinal Modulus</Data></Cell>";
                if (isMechAvail) writeSafeCell(file, bp.longitudinalModulus);
                else file << "<Cell><Data ss:Type=\"String\">compound is not available in database(MECHANICAL)</Data></Cell>";
                file << "<Cell><Data ss:Type=\"String\">GPa</Data></Cell></Row>\n";
            }
            if (params.count("poissons_ratio")) {
                file << "  <Row><Cell><Data ss:Type=\"String\">Poisson's Ratio</Data></Cell>";
                if (isMechAvail) writeSafeCell(file, bp.poissonsRatio);
                else file << "<Cell><Data ss:Type=\"String\">compound is not available in database(MECHANICAL)</Data></Cell>";
                file << "<Cell><Data ss:Type=\"String\">dimensionless</Data></Cell></Row>\n";
            }
            if (params.count("hardness")) {
                file << "  <Row><Cell><Data ss:Type=\"String\">Vickers Hardness</Data></Cell>";
                if (isMechAvail) writeSafeCell(file, bp.hardness);
                else file << "<Cell><Data ss:Type=\"String\">compound is not available in database(MECHANICAL)</Data></Cell>";
                file << "<Cell><Data ss:Type=\"String\">GPa</Data></Cell></Row>\n";
            }
            if (params.count("fractalbondconnectivity")) {
                file << "  <Row><Cell><Data ss:Type=\"String\">Fractal Bond Connectivity</Data></Cell>";
                if (isMechAvail) writeSafeCell(file, bp.fractalBondConnectivity);
                else file << "<Cell><Data ss:Type=\"String\">compound is not available in database(MECHANICAL)</Data></Cell>";
                file << "<Cell><Data ss:Type=\"String\">dimensionless</Data></Cell></Row>\n";
            }
        }
        
        if (wantOptical) {
            file << "  <Row><Cell><Data ss:Type=\"String\">--- Optical Properties ---</Data></Cell><Cell/><Cell/></Row>\n";
            if (params.count("refractive_index")) {
                file << "  <Row><Cell><Data ss:Type=\"String\">Refractive Index (n)</Data></Cell>";
                writeSafeCell(file, bp.refractiveIndex);
                file << "<Cell><Data ss:Type=\"String\">dimensionless</Data></Cell></Row>\n";
            }
            if (params.count("dielectric_constant")) {
                file << "  <Row><Cell><Data ss:Type=\"String\">Dielectric Constant (ε)</Data></Cell>";
                writeSafeCell(file, bp.dielectricConstant);
                file << "<Cell><Data ss:Type=\"String\">dimensionless</Data></Cell></Row>\n";
            }
            if (params.count("opt_dielectric_constant")) {
                file << "  <Row><Cell><Data ss:Type=\"String\">Optical Dielectric Constant (ε_∞)</Data></Cell>";
                writeSafeCell(file, bp.optDielectricConstant);
                file << "<Cell><Data ss:Type=\"String\">dimensionless</Data></Cell></Row>\n";
            }
            if (params.count("reflection_loss")) {
                file << "  <Row><Cell><Data ss:Type=\"String\">Reflection Loss (RL)</Data></Cell>";
                writeSafeCell(file, bp.reflectionLoss);
                file << "<Cell><Data ss:Type=\"String\">dimensionless</Data></Cell></Row>\n";
            }
            if (params.count("molar_refractivity")) {
                file << "  <Row><Cell><Data ss:Type=\"String\">Molar Refractivity (Rm)</Data></Cell>";
                writeSafeCell(file, bp.molarRefractivity);
                file << "<Cell><Data ss:Type=\"String\">cm3/mol</Data></Cell></Row>\n";
            }
            if (params.count("metallization")) {
                file << "  <Row><Cell><Data ss:Type=\"String\">Metallization Criterion (M)</Data></Cell>";
                writeSafeCell(file, bp.metallization);
                file << "<Cell><Data ss:Type=\"String\">dimensionless</Data></Cell></Row>\n";
            }
            if (params.count("molar_polarizability")) {
                file << "  <Row><Cell><Data ss:Type=\"String\">Molar Polarizability (α_m)</Data></Cell>";
                writeSafeCell(file, bp.molarPolarizability);
                file << "<Cell><Data ss:Type=\"String\">10^-24 cm3</Data></Cell></Row>\n";
            }
            if (params.count("electronic_polarizability")) {
                file << "  <Row><Cell><Data ss:Type=\"String\">Electronic Polarizability (α_e)</Data></Cell>";
                writeSafeCell(file, bp.electronicPolarizability);
                file << "<Cell><Data ss:Type=\"String\">10^-24 cm3</Data></Cell></Row>\n";
            }
            if (params.count("optical_transmission")) {
                file << "  <Row><Cell><Data ss:Type=\"String\">Transmission Coefficient (T)</Data></Cell>";
                writeSafeCell(file, bp.transmissionCoefficient);
                file << "<Cell><Data ss:Type=\"String\">dimensionless</Data></Cell></Row>\n";
            }
            if (params.count("opt_electronegativity")) {
                file << "  <Row><Cell><Data ss:Type=\"String\">Optical Electronegativity (χ*)</Data></Cell>";
                writeSafeCell(file, bp.optElectronegativity);
                file << "<Cell><Data ss:Type=\"String\">dimensionless</Data></Cell></Row>\n";
            }
            if (params.count("linear_susceptibility")) {
                file << "  <Row><Cell><Data ss:Type=\"String\">Linear Dielectric Susceptibility (χ(1))</Data></Cell>";
                writeSafeCell(file, bp.linearSusceptibility);
                file << "<Cell><Data ss:Type=\"String\">dimensionless</Data></Cell></Row>\n";
            }
            if (params.count("nonlinear_susceptibility")) {
                file << "  <Row><Cell><Data ss:Type=\"String\">Non-linear Optical Susceptibility (χ(3))</Data></Cell>";
                writeSafeCell(file, bp.nonlinearSusceptibility * 1e16);
                file << "<Cell><Data ss:Type=\"String\">10^-16 esu</Data></Cell></Row>\n";
            }
            if (params.count("nonlinear_refractive_index")) {
                file << "  <Row><Cell><Data ss:Type=\"String\">Non-linear Refractive Index (n2)</Data></Cell>";
                writeSafeCell(file, bp.nonlinearRefractiveIndex * 1e15);
                file << "<Cell><Data ss:Type=\"String\">10^-15 esu</Data></Cell></Row>\n";
            }
        }
    }
    file << " </Table>\n </Worksheet>\n";

    // --- SHEET 2: INTERACTION PARAMETERS (only selected columns) ---
    if (wantInteraction) {
        file << " <Worksheet ss:Name=\"Interaction_Parameters\">\n <Table>\n";
        // Header row
        file << "  <Row><Cell><Data ss:Type=\"String\">Energy (MeV)</Data></Cell>";
        if (hasIsotopes) file << "<Cell><Data ss:Type=\"String\">Isotope</Data></Cell>";
        if (wantMAC)  file << "<Cell><Data ss:Type=\"String\">MAC</Data></Cell>";
        if (wantLAC)  file << "<Cell><Data ss:Type=\"String\">LAC</Data></Cell>";
        if (wantMFP)  file << "<Cell><Data ss:Type=\"String\">MFP</Data></Cell>";
        if (wantHVL)  file << "<Cell><Data ss:Type=\"String\">HVL</Data></Cell>";
        if (wantTVL)  file << "<Cell><Data ss:Type=\"String\">TVL</Data></Cell>";
        if (wantZeff) file << "<Cell><Data ss:Type=\"String\">Zeff</Data></Cell>";
        if (wantNe)   file << "<Cell><Data ss:Type=\"String\">Ne</Data></Cell>";
        file << "</Row>\n";
        // Data rows
        for (size_t i = 0; i < macData.size(); ++i) {
            file << "  <Row>";
            writeSafeCell(file, macData[i].energy);
            if (hasIsotopes) {
                auto it = energyToIsotope.find(macData[i].energy);
                if (it != energyToIsotope.end())
                    file << "   <Cell><Data ss:Type=\"String\">" << it->second << "</Data></Cell>\n";
                else
                    file << "   <Cell><Data ss:Type=\"String\"></Data></Cell>\n";
            }
            if (wantMAC)  writeSafeCell(file, macData[i].mac);
            if (wantLAC)  { if(i < lacData.size())  writeSafeCell(file, lacData[i].mac);  else file << "   <Cell/>\n"; }
            if (wantMFP)  { if(i < mfpData.size())  writeSafeCell(file, mfpData[i].mac);  else file << "   <Cell/>\n"; }
            if (wantHVL)  { if(i < hvlData.size())  writeSafeCell(file, hvlData[i].mac);  else file << "   <Cell/>\n"; }
            if (wantTVL)  { if(i < tvlData.size())  writeSafeCell(file, tvlData[i].mac);  else file << "   <Cell/>\n"; }
            if (wantZeff) { if(i < zeffData.size()) writeSafeCell(file, zeffData[i].mac); else file << "   <Cell/>\n"; }
            if (wantNe)   { if(i < neData.size())   writeSafeCell(file, neData[i].mac);   else file << "   <Cell/>\n"; }
            file << "</Row>\n";
        }
        file << " </Table>\n </Worksheet>\n";
    }

    // --- SHEET 3, 4, 5: THICKNESS ANALYSIS (TF, RPE, LEQ) - only if selected ---
    auto writeCompSheet = [&](string name, const map<double, vector<AttenuationResult>>& dMap, string lbl) {
        file << " <Worksheet ss:Name=\"" << name << "\">\n <Table>\n";
        file << "  <Row><Cell><Data ss:Type=\"String\">Energy (MeV)</Data></Cell>";
        if (hasIsotopes) file << "<Cell><Data ss:Type=\"String\">Isotope</Data></Cell>";
        for(double t : t_values) file << "<Cell><Data ss:Type=\"String\">" << lbl << " (" << t << "cm)</Data></Cell>";
        file << "</Row>\n";
        for (size_t i = 0; i < macData.size(); ++i) {
            file << "  <Row>"; writeSafeCell(file, macData[i].energy);
            if (hasIsotopes) {
                auto it = energyToIsotope.find(macData[i].energy);
                if (it != energyToIsotope.end())
                    file << "   <Cell><Data ss:Type=\"String\">" << it->second << "</Data></Cell>\n";
                else
                    file << "   <Cell><Data ss:Type=\"String\"></Data></Cell>\n";
            }
            for(double t : t_values) writeSafeCell(file, dMap.at(t)[i].mac);
            file << "</Row>\n";
        }
        file << " </Table>\n </Worksheet>\n";
    };
    if (wantTF)  writeCompSheet("TF_Analysis", tfMap, "TF");
    if (wantRPE) writeCompSheet("RPE_Analysis", rpeMap, "RPE");
    if (wantLeq) writeCompSheet("Leq_Analysis", leqMap, "Leq");

    // --- SHEET 6 & 7: GP PARAMETERS - only if selected ---
    if (wantGP || wantZeq) {
        auto writeGPSheet = [&](string name, bool isAbs) {
            file << " <Worksheet ss:Name=\"" << name << "\">\n <Table>\n";
            file << "  <Row><Cell><Data ss:Type=\"String\">Energy</Data></Cell>";
            if (wantZeq) file << "<Cell><Data ss:Type=\"String\">Zeq</Data></Cell>";
            if (wantGP) {
                file << "<Cell><Data ss:Type=\"String\">b</Data></Cell><Cell><Data ss:Type=\"String\">c</Data></Cell><Cell><Data ss:Type=\"String\">a</Data></Cell>";
                file << "<Cell><Data ss:Type=\"String\">Xk</Data></Cell><Cell><Data ss:Type=\"String\">d</Data></Cell>";
            }
            file << "</Row>\n";
            for (size_t i = 0; i < gpData.size(); ++i) {
                auto p = isAbs ? gpData[i].absorption : gpData[i].exposure;
                file << "  <Row>";
                writeSafeCell(file, gpData[i].energy);
                if (wantZeq) {
                    if(i < zeqData.size()) writeSafeCell(file, zeqData[i].zeq); else file << "   <Cell/>\n";
                }
                if (wantGP) {
                    writeSafeCell(file, p.b); writeSafeCell(file, p.c); writeSafeCell(file, p.a);
                    writeSafeCell(file, p.Xk); writeSafeCell(file, p.d);
                }
                file << "  </Row>\n";
            }
            file << " </Table>\n </Worksheet>\n";
        };
        writeGPSheet("GP_Absorption", true);
        writeGPSheet("GP_Exposure", false);
    }

    // --- SHEET 8 & 9: BUILDUP (EBF & EABF) - only if selected ---
    auto writeBuildup = [&](string name, bool isEbf) {
        file << " <Worksheet ss:Name=\"" << name << "\">\n <Table>\n";
        file << "  <Row><Cell><Data ss:Type=\"String\">E (MeV)</Data></Cell>";
        for(double x : x_mfp) file << "<Cell><Data ss:Type=\"String\">x=" << x << " mfp</Data></Cell>";
        file << "</Row>\n";
        for (const auto& r : buData) {
            file << "  <Row>"; writeSafeCell(file, r.energy);
            for(double v : (isEbf ? r.ebf : r.eabf)) writeSafeCell(file, v);
            file << "</Row>\n";
        }
        file << " </Table>\n </Worksheet>\n";
    };
    if (wantEBF)  writeBuildup("EBF", true);
    if (wantEABF) writeBuildup("EABF", false);



    file << "</Workbook>\n";
    file.close();
    return filename;
}

// Helper to read entire file into a string
string readFileToString(const string& path) {
    ifstream f(path, ios::binary);
    if (!f.is_open()) return "";
    ostringstream ss;
    ss << f.rdbuf();
    return ss.str();
}

// --- USER MANAGEMENT SYSTEM ---
#include <random>
struct UserData {
    string password;
    string email;
    bool verified;
    string verificationCode;
    vector<string> history;
};
map<string, UserData> userDB;

void loadUsers() {
    ifstream f("users.json");
    if(f.good()) {
        json j;
        try {
            f >> j;
            for(auto& el : j.items()) {
                string uname = el.key();
                userDB[uname].password = el.value().value("password", "");
                userDB[uname].email = el.value().value("email", "");
                userDB[uname].verified = el.value().value("verified", false);
                userDB[uname].verificationCode = el.value().value("verificationCode", "");
                if (el.value().contains("history")) {
                    for(auto& h : el.value()["history"]) {
                        userDB[uname].history.push_back(h.get<string>());
                    }
                }
            }
        } catch(...) {}
    }
}

void saveUsers() {
    json j;
    for(auto& pair : userDB) {
        j[pair.first]["password"] = pair.second.password;
        j[pair.first]["email"] = pair.second.email;
        j[pair.first]["verified"] = pair.second.verified;
        j[pair.first]["verificationCode"] = pair.second.verificationCode;
        j[pair.first]["history"] = pair.second.history;
    }
    ofstream f("users.json");
    f << j.dump(4);
}

string generateVerificationCode() {
    random_device rd;
    mt19937 gen(rd());
    uniform_int_distribution<> distrib(100000, 999999);
    return to_string(distrib(gen));
}

